public final class KeychainKeyStore {
    private let service: String
    private let account: String
    private let accessGroup: String?

    public init(service: String = Bundle.main.bundleIdentifier ?? "BankingModule",
                account: String = "BankingModule.MasterKey.v1",
                accessGroup: String? = nil) {
        self.service = service
        self.account = account
        self.accessGroup = accessGroup
    }

    public func loadOrCreateKey() throws -> SymmetricKey {
        if let data = try loadKeyData() {
            return SymmetricKey(data: data)
        }
        let key = SymmetricKey(size: .bits256)
        let data = key.withUnsafeBytes { Data($0) }
        try saveKeyData(data)
        return key
    }

    private func loadKeyData() throws -> Data? {
        var query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        if let accessGroup { query[kSecAttrAccessGroup as String] = accessGroup }

        var item: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &item)

        if status == errSecItemNotFound { return nil }
        guard status == errSecSuccess else { throw BankingError.keychainFailure(status) }
        guard let data = item as? Data else { throw BankingError.keychainFailure(errSecInternalError) }
        return data
    }

    private func saveKeyData(_ data: Data) throws {
        let access = SecAccessControlCreateWithFlags(nil,
                                                    kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly,
                                                    [],
                                                    nil)

        var attributes: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account,
            kSecValueData as String: data
        ]
        if let access { attributes[kSecAttrAccessControl as String] = access }
        if let accessGroup { attributes[kSecAttrAccessGroup as String] = accessGroup }

        let status = SecItemAdd(attributes as CFDictionary, nil)
        if status == errSecDuplicateItem {
            try updateKeyData(data)
            return
        }
        guard status == errSecSuccess else { throw BankingError.keychainFailure(status) }
    }

    private func updateKeyData(_ data: Data) throws {
        var query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account
        ]
        if let accessGroup { query[kSecAttrAccessGroup as String] = accessGroup }

        let update: [String: Any] = [kSecValueData as String: data]
        let status = SecItemUpdate(query as CFDictionary, update as CFDictionary)
        guard status == errSecSuccess else { throw BankingError.keychainFailure(status) }
    }
}

