public final class CryptoEngine {
    private let keyStore: KeychainKeyStore
    private lazy var key: SymmetricKey = {
        // Fallback only; should not fail in practice after init(load).
        return SymmetricKey(size: .bits256)
    }()

    public init(keyStore: KeychainKeyStore = KeychainKeyStore()) throws {
        self.keyStore = keyStore
        self.key = try keyStore.loadOrCreateKey()
    }

    public func encrypt(_ plaintext: Data, aad: Data? = nil) throws -> Data {
        do {
            let nonce = AES.GCM.Nonce()
            let sealed = try AES.GCM.seal(plaintext, using: key, nonce: nonce, authenticating: aad ?? Data())
            let blob = EncryptedBlob(nonce: Data(sealed.nonce),
                                     ciphertext: sealed.ciphertext,
                                     tag: sealed.tag)
            return try JSONEncoder().encode(blob)
        } catch {
            throw BankingError.cryptoFailure
        }
    }

    public func decrypt(_ encrypted: Data, aad: Data? = nil) throws -> Data {
        do {
            let blob = try JSONDecoder().decode(EncryptedBlob.self, from: encrypted)
            let nonce = try AES.GCM.Nonce(data: blob.nonce)
            let sealed = try AES.GCM.SealedBox(nonce: nonce, ciphertext: blob.ciphertext, tag: blob.tag)
            return try AES.GCM.open(sealed, using: key, authenticating: aad ?? Data())
        } catch {
            throw BankingError.cryptoFailure
        }
    }
}

