public final class EncryptedFileLedgerStorage: LedgerStorage {
    private let crypto: CryptoEngine
    private let fileURL: URL
    private let aad: Data

    public init(crypto: CryptoEngine,
                filename: String = "ledger.secure",
                directory: FileManager.SearchPathDirectory = .applicationSupportDirectory) throws {
        self.crypto = crypto

        let fm = FileManager.default
        let dir = try fm.url(for: directory, in: .userDomainMask, appropriateFor: nil, create: true)
        let bundleId = Bundle.main.bundleIdentifier ?? "BankingModule"
        let moduleDir = dir.appendingPathComponent(bundleId, isDirectory: true)
        if !fm.fileExists(atPath: moduleDir.path) {
            try fm.createDirectory(at: moduleDir, withIntermediateDirectories: true)
        }
        self.fileURL = moduleDir.appendingPathComponent(filename, isDirectory: false)
        self.aad = Data((bundleId + "|" + filename).utf8)
    }

    public func load() async throws -> LedgerSnapshot {
        let fm = FileManager.default
        guard fm.fileExists(atPath: fileURL.path) else {
            return LedgerSnapshot()
        }
        do {
            let encrypted = try Data(contentsOf: fileURL, options: [.mappedIfSafe])
            let plaintext = try crypto.decrypt(encrypted, aad: aad)
            do {
                return try JSONDecoder().decode(LedgerSnapshot.self, from: plaintext)
            } catch {
                throw BankingError.decodingFailure
            }
        } catch let err as BankingError {
            throw err
        } catch {
            throw BankingError.fileIOFailure
        }
    }

    public func save(_ snapshot: LedgerSnapshot) async throws {
        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        let plaintext: Data
        do {
            plaintext = try encoder.encode(snapshot)
        } catch {
            throw BankingError.encodingFailure
        }

        let encrypted = try crypto.encrypt(plaintext, aad: aad)
        do {
            let fm = FileManager.default
            let dir = fileURL.deletingLastPathComponent()
            if !fm.fileExists(atPath: dir.path) {
                try fm.createDirectory(at: dir, withIntermediateDirectories: true)
            }
            try encrypted.write(to: fileURL, options: [.atomic, .completeFileProtection])
        } catch {
            throw BankingError.fileIOFailure
        }
    }
}

// MARK: - Banking Engine (Secure Transaction Handling)

public actor BankingEngine {
    private let storage: LedgerStorage
    private var snapshot: LedgerSnapshot
    private let maxReferenceLength: Int

    public init(storage: LedgerStorage, maxReferenceLength: Int = 140) async throws {
        self.storage = storage
        self.snapshot = try await storage.load()
        self.maxReferenceLength = maxReferenceLength
    }

    public func listAccounts() -> [Account] {
        snapshot.accounts.sorted { $0.name.localizedCaseInsensitiveCompare($1.name) == .orderedAscending }
    }

    public func listTransactions(accountId: UUID) throws -> [Transaction] {
        guard snapshot.accounts.contains(where: { $0.id == accountId }) else { throw BankingError.accountNotFound }
        return snapshot.transactions
            .filter { $0.accountId == accountId }
            .sorted { $0.createdAt > $1.createdAt }
    }

    public func getAccount(id: UUID) -> Account? {
        snapshot.accounts.first(where: { $0.id == id })
    }

    public func createAccount(name: String, currencyCode: String, openingBalanceMinor: Int64 = 0) async throws -> Account {
        let account = Account(name: name,
                              currencyCode: currencyCode,
                              balanceMinor: openingBalanceMinor,
                              updatedAt: Date())
        snapshot.accounts.append(account)
        snapshot.updatedAt = Date()
        try await storage.save(snapshot)
        return account
    }

    public func deleteAccount(id: UUID) async throws {
        snapshot.accounts.removeAll { $0.id == id }
        snapshot.transactions.removeAll { $0.accountId == id }
        snapshot.updatedAt = Date()
        try await storage.save(snapshot)
    }

    public func applyTransaction(accountId: UUID,
                                 type: TransactionType,
                                 amountMinor: Int64,
                                 reference: String? = nil,
                                 idempotencyKey: String) async throws -> Transaction {
        guard amountMinor > 0 else { throw BankingError.invalidAmount }
        guard !idempotencyKey.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else { throw BankingError.invalidAmount }

        if snapshot.processedIdempotencyKeys.contains(idempotencyKey) {
            throw BankingError.duplicateTransaction
        }

        guard let idx = snapshot.accounts.firstIndex(where: { $0.id == accountId }) else {
            throw BankingError.accountNotFound
        }

        let cleanReference: String?
        if let reference {
            let trimmed = reference.trimmingCharacters(in: .whitespacesAndNewlines)
            cleanReference = trimmed.isEmpty ? nil : String(trimmed.prefix(maxReferenceLength))
        } else {
            cleanReference = nil
        }

        var account = snapshot.accounts[idx]
        let delta: Int64 = (type == .credit) ? amountMinor : -amountMinor

        if type == .debit && account.balanceMinor + delta < 0 {
            throw BankingError.insufficientFunds
        }

        account.balanceMinor += delta
        account.updatedAt = Date()
        snapshot.accounts[idx] = account

        let tx = Transaction(accountId: accountId,
                             type: type,
                             amountMinor: amountMinor,
                             createdAt: Date(),
                             reference: cleanReference,
                             idempotencyKey: idempotencyKey)

        snapshot.transactions.append(tx)
        snapshot.processedIdempotencyKeys.insert(idempotencyKey)
        snapshot.updatedAt = Date()
        try await storage.save(snapshot)

        return tx
    }

    public func balanceString(accountId: UUID, locale: Locale = .current) throws -> String {
        guard let account = snapshot.accounts.first(where: { $0.id == accountId }) else {
            throw BankingError.accountNotFound
        }
        return MoneyFormatter.string(minorUnits: account.balanceMinor, currencyCode: account.currencyCode, locale: locale)
    }
}

