public final class BankingModule {
    public let engine: BankingEngine

    public init() async throws {
        let crypto = try CryptoEngine()
        let storage = try EncryptedFileLedgerStorage(crypto: crypto)
        self.engine = try await BankingEngine(storage: storage)
    }

    public func accountRows(locale: Locale = .current) async -> [AccountRowViewModel] {
        await engine.listAccounts().map { acct in
            let text = MoneyFormatter.string(minorUnits: acct.balanceMinor, currencyCode: acct.currencyCode, locale: locale)
            return AccountRowViewModel(id: acct.id, name: acct.name, balanceText: text, currencyCode: acct.currencyCode)
        }
    }

    public func transactionRows(accountId: UUID, locale: Locale = .current) async throws -> [TransactionRowViewModel] {
        let acct = await engine.getAccount(id: accountId)
        guard let acct else { throw BankingError.accountNotFound }

        let txs = try await engine.listTransactions(accountId: accountId)
        return txs.map { tx in
            let sign = (tx.type == .credit) ? 1 : -1
            let signedMinor = Int64(sign) * tx.amountMinor
            let absText = MoneyFormatter.string(minorUnits: abs(signedMinor), currencyCode: acct.currencyCode, locale: locale)
            let amountText = (tx.type == .credit) ? "+\(absText)" : "-\(absText)"
            let title = tx.reference ?? (tx.type == .credit ? "Credit" : "Debit")
            let subtitle = tx.id.uuidString
            return TransactionRowViewModel(id: tx.id,
                                           title: title,
                                           subtitle: subtitle,
                                           amountText: amountText,
                                           isCredit: tx.type == .credit,
                                           createdAt: tx.createdAt)
        }
    }
}

// MARK: - Convenience

private func abs(_ x: Int64) -> Int64 { x >= 0 ? x : (x == Int64.min ? Int64.max : -x) }